    async function reloadUserMusicStateFromSupabase(availableSongs = songs, availableVideos = videos, availableAlbums = albums) {
        if (!accountUserId) {
            return null;
        }
        let response: Response;
        try {
            response = await desktopActionFetch(`/api/user-music-state?userId=${encodeURIComponent(accountUserId)}`, { cache: "no-store", requireAuth: true });
        }
        catch {
            return null;
        }
        const data = (await response.json().catch(() => ({}))) as {
            hasState?: boolean;
            libraryIds?: string[];
            recentlyPlayed?: RecentPlay[];
            playlists?: Playlist[];
            activePlaylistId?: string;
            setupRequired?: boolean;
            error?: string;
        };
        if (!response.ok) {
            showToast("Saved library state could not be loaded. Local browser state is still available.", "error");
            return null;
        }
        if (data.setupRequired) {
            return null;
        }
        if (!data.hasState) {
            return null;
        }
        const remoteRecent = normalizeRecentForSongs(data.recentlyPlayed || [], availableSongs, availableVideos, availableAlbums);
        let mergedRecent = remoteRecent;
        setRecentlyPlayed((previous) => {
            const localRecent = normalizeRecentForSongs(previous, availableSongs, availableVideos, availableAlbums);
            mergedRecent = mergeRecentPlays(localRecent, remoteRecent);
            return mergedRecent;
        });
        await confirmAuthenticatedFromApi(accountUserId);
        return { recentlyPlayed: mergedRecent };
    }
