    function addToQueue(song: Song) {
        const normalized = normalizeSongToQueueItem({
            ...song,
            id: song.id,
            title: song.title,
            artist: song.artist,
            artistName: song.artist,
            audio: song.audio,
            audioUrl: song.audio,
            playableUrl: song.audio,
            storagePath: song.audioPath || "",
            audioPath: song.audioPath || "",
            cover: song.cover,
            artworkUrl: song.cover,
            thumbnail: song.cover,
            duration: song.time,
            ownerId: song.ownerId || "",
        } as unknown as Record<string, unknown>);
        if (!normalized.item) {
            showToast(normalized.error || "Song could not be queued.", "error");
            return;
        }
        const result = addQueueItem(normalized.item);
        showToast(result.message, result.toastKind);
    }
    function addVideoToQueue(video: VideoItem) {
        // MUST use the same addQueueItem() as songs — no separate video queue state.
        const catalog = videos.find((item) => item.id === video.id) || video;
        const resolvedPlayableUrl = String(
            getVideoPlaybackUrl(catalog)
            || getVideoPlaybackUrl(video)
            || (catalog as { videoUrl?: string }).videoUrl
            || (catalog as { video_url?: string }).video_url
            || (catalog as { playableUrl?: string }).playableUrl
            || (video as { videoUrl?: string }).videoUrl
            || (video as { video_url?: string }).video_url
            || (video as { playableUrl?: string }).playableUrl
            || "",
        ).trim();
        const rawStoragePath = String(
            (catalog as { storagePath?: string }).storagePath
            || (catalog as { storage_path?: string }).storage_path
            || (video as { storagePath?: string }).storagePath
            || (video as { storage_path?: string }).storage_path
            || "",
        ).trim();
        const thumbnail = catalog.cover || video.cover || catalog.thumbnail_url || video.thumbnail_url || "";
        const artist = catalog.creator || video.creator || catalog.artistName || video.artistName || "";
        const normalized = normalizeVideoToQueueItem({
            ...catalog,
            ...video,
            id: catalog.id || video.id,
            title: catalog.title || video.title,
            artist,
            artistName: artist,
            creator: artist,
            playableUrl: resolvedPlayableUrl,
            videoUrl: resolvedPlayableUrl,
            video_url: resolvedPlayableUrl,
            storagePath: rawStoragePath,
            storage_path: rawStoragePath,
            cover: thumbnail,
            artworkUrl: thumbnail,
            thumbnail,
            thumbnail_url: thumbnail,
            ownerId: catalog.ownerId || video.ownerId || "",
            duration: (catalog as { duration?: number | string }).duration
                ?? (video as { duration?: number | string }).duration
                ?? null,
        } as unknown as Record<string, unknown>);
        if (!normalized.item) {
            showToast(normalized.error || "Video could not be queued.", "error");
            return;
        }
        const result = addQueueItem(normalized.item);
        showToast(result.message, result.toastKind);
    }
    function addAlbumToQueue(album: Album | ResolvedAlbum) {
        const resolvedAlbum = resolvedAlbums.find((item) => item.id === album.id) || resolveAlbumTracksFromPools(album);
        const albumSongs = uniqueSongs(resolvedAlbum.songs);
        const albumVideos = uniqueVideos(resolvedAlbum.videos.map((video) => normalizeVideoForPlayback(video)));
        if (albumSongs.length === 0 && albumVideos.length === 0) {
            showToast("This album has no queueable tracks.", "info");
            return;
        }
        let addedAny = false;
        for (const song of albumSongs) {
            const result = addSongRecordToQueue(song as unknown as Record<string, unknown>);
            if (result.added)
                addedAny = true;
        }
        for (const video of albumVideos) {
            const rawVideoUrl = String(video.videoUrl || (video as { video_url?: string }).video_url || "").trim();
            const rawStoragePath = String(video.storagePath || (video as { storage_path?: string }).storage_path || "").trim();
            const result = addVideoRecordToQueue({
                ...video,
                id: video.id,
                title: video.title,
                artist: video.creator || video.artistName || "",
                artistName: video.artistName || video.creator || "",
                creator: video.creator || video.artistName || "",
                playableUrl: rawVideoUrl,
                videoUrl: rawVideoUrl,
                video_url: rawVideoUrl,
                storagePath: rawStoragePath,
                storage_path: rawStoragePath,
                cover: video.cover,
                artworkUrl: video.cover || "",
            } as unknown as Record<string, unknown>);
            if (result.added)
                addedAny = true;
        }
        showToast(addedAny ? "Added to queue." : "Already in queue.", addedAny ? "success" : "info");
    }
    async function toggleLike(songId: string) {
        if (!guardDesktopProtectedAction("toggle-like")) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        const song = songs.find((item) => item.id === songId);
        const wasLiked = likedIds.includes(songId);
        const previousLikedIds = likedIds;
        const previousLikes = song?.likes || 0;
        const nextLikedIds = wasLiked ? likedIds.filter((id) => id !== songId) : uniqueIds([...likedIds, songId]);
        const optimisticLikes = Math.max(0, previousLikes + (wasLiked ? -1 : 1));
        setLikedIds(nextLikedIds);
        setSongs((previous) => previous.map((item) => (item.id === songId ? { ...item, likes: optimisticLikes } : item)));
        try {
            const response = await dispatchDesktopSongLike({ songId, like: !wasLiked });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
                likes?: number;
                likedByUser?: boolean;
            };
            if (!response.ok) {
                setLikedIds(previousLikedIds);
                setSongs((previous) => previous.map((item) => (item.id === songId ? { ...item, likes: previousLikes } : item)));
                reportPlatformError("like", wasLiked ? "song-unlike" : "song-like", data.error || "Could not update song like.", { songId });
                showToast(data.error || "Could not update song like.", "error");
                return;
            }
            setLikedIds((previous) => data.likedByUser ? uniqueIds([...previous, songId]) : previous.filter((id) => id !== songId));
            if (typeof data.likes === "number") {
                setSongs((previous) => previous.map((item) => (item.id === songId ? { ...item, likes: data.likes || 0 } : item)));
            }
            showToast(data.likedByUser ? "Song liked." : "Song unliked.", "success");
            if (data.likedByUser && song) {
                pushNotification("New like", `${song.title} was liked.`, "song", song.id);
            }
        }
        catch (error) {
            setLikedIds(previousLikedIds);
            setSongs((previous) => previous.map((item) => (item.id === songId ? { ...item, likes: previousLikes } : item)));
            reportPlatformError("like", wasLiked ? "song-unlike" : "song-like", error instanceof Error ? error.message : String(error), { songId });
            showToast("Could not update song like. Check your connection and try again.", "error");
        }
    }
    function openArtistProfile(artistName: string) {
        const id = createArtistId(artistName);
        setArtistProfiles((previous) => {
            if (previous.some((artist) => artist.id === id))
                return previous;
            return buildArtistProfiles(songs, previous);
        });
        setActiveArtistId(id);
        setSearch("");
        setSearchInput("");
        setShowUpload(false);
        setView("Artist Profile");
    }
    async function toggleArtistFollow(artistId: string, artistName?: string) {
        if (!guardDesktopProtectedAction("toggle-follow")) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        const artist = mergedArtistProfiles.find((item) => item.id === artistId);
        const name = artistName || artist?.name || artistId;
        const wasFollowing = followedArtistIds.includes(artistId);
        const nextFollowedIds = wasFollowing
            ? followedArtistIds.filter((id) => id !== artistId)
            : uniqueIds([...followedArtistIds, artistId]);
        setFollowedArtistIds(nextFollowedIds);
        setArtistFollowerCounts((previous) => ({
            ...previous,
            [artistId]: Math.max(0, (previous[artistId] || 0) + (wasFollowing ? -1 : 1)),
        }));
        try {
            const response = await dispatchDesktopArtistFollow({
                artistId,
                artistName: name,
                follow: !wasFollowing,
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
                followerCount?: number;
                followerCounts?: Record<string, number>;
            };
            if (!response.ok) {
                setFollowedArtistIds(followedArtistIds);
                setArtistFollowerCounts((previous) => ({
                    ...previous,
                    [artistId]: Math.max(0, (previous[artistId] || 0) + (wasFollowing ? 1 : -1)),
                }));
                reportPlatformError("follow", wasFollowing ? "artist-unfollow" : "artist-follow", data.error || "Could not update artist follow.", { artistId, artistName: name });
                showToast(data.error || "Could not update artist follow.", "error");
                return;
            }
            if (typeof data.followerCount === "number") {
                setArtistFollowerCounts((previous) => ({ ...previous, [artistId]: data.followerCount || 0 }));
            }
            else if (data.followerCounts?.[artistId] !== undefined) {
                setArtistFollowerCounts((previous) => ({ ...previous, [artistId]: data.followerCounts?.[artistId] || 0 }));
            }
            showToast(wasFollowing ? `Unfollowed ${name}.` : `Following ${name}.`, "success");
            if (!wasFollowing) {
                pushNotification("New follower", `You followed ${name}.`, "artist", artistId);
            }
        }
        catch (error) {
            setFollowedArtistIds(followedArtistIds);
            setArtistFollowerCounts((previous) => ({
                ...previous,
                [artistId]: Math.max(0, (previous[artistId] || 0) + (wasFollowing ? 1 : -1)),
            }));
            reportPlatformError("follow", wasFollowing ? "artist-unfollow" : "artist-follow", error instanceof Error ? error.message : String(error), { artistId, artistName: name });
            showToast("Could not update artist follow. Check your connection and try again.", "error");
        }
    }
    async function shareArtist(artist: ArtistProfile) {
        const shareText = `Listen to ${artist.name} on Z Music.`;
        const shareUrl = `${window.location.origin}${window.location.pathname}#artist-${artist.id}`;
        try {
            if (navigator.share) {
                await navigator.share({ title: artist.name, text: shareText, url: shareUrl });
                return;
            }
            await navigator.clipboard.writeText(`${shareText} ${shareUrl}`);
            alert("Artist link copied.");
        }
        catch {
            alert("Artist share was canceled.");
        }
    }
