    function openSaveQueueAsPlaylistDialog() {
        if (!isAuthenticated || !String(accountUserId || "").trim()) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        if (queueCount === 0 || mediaQueueItems.length === 0) {
            showToast("Queue is empty.", "info");
            return;
        }
        if (saveQueuePlaylistBusy || saveQueuePlaylistLockRef.current) {
            return;
        }
        setSaveQueuePlaylistName(`Queue ${new Date().toLocaleDateString()}`);
        setShowSaveQueuePlaylistDialog(true);
    }
    async function saveQueueAsPlaylist() {
        if (saveQueuePlaylistLockRef.current || saveQueuePlaylistBusy) {
            return;
        }
        if (!guardDesktopProtectedAction("save-queue-playlist")) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        if (!isAuthenticated || !String(accountUserId || "").trim()) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        if (queueCount === 0 || mediaQueueItems.length === 0) {
            showToast("Queue is empty.", "info");
            return;
        }
        const name = String(saveQueuePlaylistName || "").trim();
        if (!name) {
            showToast("Name the playlist first.", "info");
            return;
        }

        const orderedItems = mediaQueueItems.slice();
        const songIds = orderedItems.filter((item) => item.mediaType === "song").map((item) => item.id);
        const videoIds = orderedItems.filter((item) => item.mediaType === "video").map((item) => item.id);
        const playlistType = songIds.length > 0 && videoIds.length > 0
            ? "mixed"
            : videoIds.length > 0
                ? "video"
                : "song";
        const cover = orderedItems[0]?.artworkUrl || orderedItems[0]?.thumbnail || DEFAULT_PLAYLIST_COVER;
        const now = new Date().toISOString();
        const playlist: Playlist = {
            id: crypto.randomUUID(),
            name,
            cover,
            playlistType,
            songIds,
            videoIds,
            createdAt: now,
            updatedAt: now,
        };

        saveQueuePlaylistLockRef.current = true;
        setSaveQueuePlaylistBusy(true);
        setPlaylists((previous) => [playlist, ...previous]);
        setActivePlaylistId(playlist.id);
        setPlaylistContentTab(playlistType === "video" ? "Videos" : "Songs");
        try {
            const response = await dispatchDesktopCreatePlaylist({
                id: playlist.id,
                name: playlist.name,
                cover: playlist.cover,
                playlistType: playlist.playlistType,
            });
            const data = (await response.json().catch(() => ({}))) as {
                playlist?: Playlist;
                error?: string;
            };
            if (!response.ok || !data.playlist) {
                showToast(data.error || "Queue playlist saved locally.", "info");
                setShowSaveQueuePlaylistDialog(false);
                return;
            }
            const savedPlaylist = data.playlist as Playlist;
            setPlaylists((previous) => previous.map((item) => (item.id === playlist.id
                ? { ...savedPlaylist, songIds, videoIds, playlistType }
                : item)));
            // Preserve queue order with sequential inserts.
            for (const item of orderedItems) {
                await desktopActionFetch("/api/playlist-items", {
                    requireAuth: true,
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    injectAuthenticatedUserId: true,
                    body: JSON.stringify({
                        playlistId: savedPlaylist.id,
                        itemId: item.id,
                        itemType: item.mediaType === "video" ? "video" : "song",
                    }),
                });
            }
            setActivePlaylistId(savedPlaylist.id);
            await reloadPlaylistsFromSupabase().catch(() => undefined);
            showToast("Queue saved as playlist.", "success");
            setShowSaveQueuePlaylistDialog(false);
        }
        catch (error) {
            reportPlatformError("playlist", "save-queue", error instanceof Error ? error.message : String(error), {
                itemCount: orderedItems.length,
            });
            showToast("Queue playlist saved locally.", "info");
            setShowSaveQueuePlaylistDialog(false);
        }
        finally {
            saveQueuePlaylistLockRef.current = false;
            setSaveQueuePlaylistBusy(false);
        }
    }
    async function createPlaylist(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        if (!guardDesktopProtectedAction("create-playlist")) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        const name = playlistForm.name.trim();
        if (!name) {
            alert("Name the playlist first.");
            return;
        }
        const now = new Date().toISOString();
        const playlist: Playlist = {
            id: crypto.randomUUID(),
            name,
            cover: playlistForm.cover.trim() || DEFAULT_PLAYLIST_COVER,
            playlistType: playlistForm.playlistType,
            songIds: [],
            videoIds: [],
            createdAt: now,
            updatedAt: now,
        };
        setPlaylists((previous) => [playlist, ...previous]);
        setActivePlaylistId(playlist.id);
        setPlaylistContentTab(playlist.playlistType === "video" ? "Videos" : "Songs");
        setPlaylistForm({ name: "", cover: "", playlistType: "mixed" });
        setView("Playlists");
        try {
            const response = await dispatchDesktopCreatePlaylist({
                id: playlist.id,
                name: playlist.name,
                cover: playlist.cover,
                playlistType: playlist.playlistType,
            });
            const data = (await response.json().catch(() => ({}))) as {
                playlist?: Playlist;
                error?: string;
            };
            if (!response.ok || !data.playlist) {
                setPlaylists((previous) => previous.filter((item) => item.id !== playlist.id));
                reportPlatformError("playlist", "create-playlist", data.error || "Playlist could not be saved.", { playlistId: playlist.id, name: playlist.name });
                showToast(data.error || "Playlist could not be saved.", "error");
                return;
            }
            setPlaylists((previous) => [data.playlist as Playlist, ...previous.filter((item) => item.id !== playlist.id)]);
            setActivePlaylistId(data.playlist.id);
            showToast("Playlist created.", "success");
        }
        catch (error) {
            setPlaylists((previous) => previous.filter((item) => item.id !== playlist.id));
            reportPlatformError("playlist", "create-playlist", error instanceof Error ? error.message : String(error), { playlistId: playlist.id, name: playlist.name });
            showToast("Playlist could not be saved. Check your connection and try again.", "error");
        }
    }
    function updatePlaylist(playlistId: string, updates: Partial<Playlist>) {
        setPlaylists((previous) => previous.map((playlist) => playlist.id === playlistId ? { ...playlist, ...updates, updatedAt: new Date().toISOString() } : playlist));
    }
    async function renamePlaylist(playlistId: string) {
        const playlist = playlists.find((item) => item.id === playlistId);
        if (!playlist)
            return;
        const nextName = window.prompt("Rename playlist", playlist.name)?.trim();
        if (!nextName)
            return;
        const previousName = playlist.name;
        updatePlaylist(playlistId, { name: nextName });
        if (!isUuid(playlistId))
            return;
        try {
            const playlistActionUserId = await resolveDesktopProtectedActionUserId("Log in before renaming playlists.");
            if (!playlistActionUserId) {
                updatePlaylist(playlistId, { name: previousName });
                return;
            }
            const response = await desktopActionFetch("/api/playlists", {
                requireAuth: true,
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ userId: playlistActionUserId, playlistId, name: nextName }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                playlist?: Playlist;
                error?: string;
            };
            if (!response.ok || !data.playlist) {
                updatePlaylist(playlistId, { name: previousName });
                reportPlatformError("playlist", "rename-playlist", data.error || "Playlist rename sync failed.", { playlistId });
                showToast(data.error || "Playlist rename could not be saved.", "error");
                return;
            }
            setPlaylists((previous) => previous.map((item) => item.id === playlistId
                ? { ...item, ...data.playlist, songIds: item.songIds, videoIds: item.videoIds }
                : item));
            showToast("Playlist renamed.", "success");
        }
        catch (error) {
            updatePlaylist(playlistId, { name: previousName });
            reportPlatformError("playlist", "rename-playlist", error instanceof Error ? error.message : String(error), { playlistId });
            showToast("Playlist rename could not be saved.", "error");
        }
    }
    async function deletePlaylist(playlistId: string) {
        const playlist = playlists.find((item) => item.id === playlistId);
        if (!playlist)
            return;
        if (!window.confirm(`Delete "${playlist.name}"?`))
            return;
        setPlaylists((previous) => previous.filter((item) => item.id !== playlistId));
        setActivePlaylistId((previous) => (previous === playlistId ? "" : previous));
        if (!isUuid(playlistId)) {
            showToast("Playlist deleted.", "success");
            return;
        }
        try {
            const playlistActionUserId = await resolveDesktopProtectedActionUserId("Log in before deleting playlists.");
            if (!playlistActionUserId) {
                return;
            }
            const response = await desktopActionFetch("/api/playlists", {
                requireAuth: true,
                method: "DELETE",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ userId: playlistActionUserId, playlistId }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
            };
            if (!response.ok) {
                reportPlatformError("playlist", "delete-playlist", data.error || "Playlist cloud delete failed.", { playlistId });
                showToast("Playlist removed locally, but cloud delete failed.", "error");
                return;
            }
            showToast("Playlist deleted.", "success");
        }
        catch (error) {
            reportPlatformError("playlist", "delete-playlist", error instanceof Error ? error.message : String(error), { playlistId });
            showToast("Playlist removed locally, but cloud delete failed.", "error");
        }
    }
