    async function downloadMediaFromCard(kind: "music" | "video", contentId: string, title: string) {
        const busyKey = `${kind}:${contentId}`;
        if (mediaDownloadLockRef.current) return;
        const userId = String(accountUserId || "").trim();
        if (!userId || !authSession?.access_token) {
            showToast(PREMIUM_LISTENER_DOWNLOAD_REQUIRED_MESSAGE, "error");
            openSubscriptionPlansForMediaDownload();
            return;
        }
        mediaDownloadLockRef.current = true;
        setMediaDownloadBusyKey(busyKey);
        showToast("Preparing download…", "info");
        try {
            const result = await downloadAuthorizedMediaFile({
                kind,
                contentId,
                userId,
                session: authSession,
            });
            if (!result.ok) {
                showToast(result.error || PREMIUM_LISTENER_DOWNLOAD_REQUIRED_MESSAGE, "error");
                if (result.openSubscriptions || result.code === "PREMIUM_LISTENER_REQUIRED" || result.status === 401) {
                    openSubscriptionPlansForMediaDownload();
                }
                return;
            }
            showToast(`Download started: ${result.filename || title}`, "success");
            // Optimistic vault sync, then refetch authoritative media_downloads history.
            const downloadedAt = new Date().toISOString();
            setMediaDownloadVault((previous) => {
                const prior = previous.find((item) => item.contentType === kind && item.contentId === contentId);
                const nextItem: MediaDownloadVaultItem = {
                    id: prior?.id || `${userId}-${kind}-${contentId}`,
                    userId,
                    contentId,
                    contentType: kind,
                    mediaType: kind === "video" ? "video" : "song",
                    title: title || result.filename || prior?.title || "Download",
                    filename: result.filename || prior?.filename || title || "Download",
                    accessSource: prior?.accessSource || "paid_listener",
                    sourceLabel: prior?.sourceLabel || "Paid listener download",
                    downloadCount: prior ? prior.downloadCount + 1 : 1,
                    downloadedAt,
                };
                return [nextItem, ...previous.filter((item) => !(item.contentType === kind && item.contentId === contentId))]
                    .sort((a, b) => new Date(b.downloadedAt).getTime() - new Date(a.downloadedAt).getTime())
                    .slice(0, 200);
            });
            void reloadMediaDownloadVault(userId, authSession.access_token);
        } catch (error) {
            showToast(error instanceof Error ? error.message : "Download failed.", "error");
        } finally {
            mediaDownloadLockRef.current = false;
            setMediaDownloadBusyKey("");
        }
    }
    function renderDesktopSongCard(song: Song, options: { variant?: "default" | "library" } = {}) {
        const isSaved = libraryIds.includes(song.id);
        const isLiked = likedIds.includes(song.id);
        const artistId = createArtistId(song.artist);
        const isFollowed = followedArtistIds.includes(artistId);
        const isQueued = isMediaQueued("song", song.id);
        const producerCredit = getProducerCreditForSong(song);
        const canDeleteTrack = canDeleteUploadedSong(song);
        const downloadBusyKey = `music:${song.id}`;
        return (<DesktopSongMediaCard
            key={song.id}
            song={song}
            variant={options.variant}
            state={{
                isLiked,
                isSaved,
                isFollowed,
                isQueued,
                isDownloading: mediaDownloadBusyKey === downloadBusyKey,
                canDelete: canDeleteTrack,
                canClaim: canClaimMedia,
                producerCredit,
                commentCount: getCommentsForItem("song", song.id).length,
                verifiedBadge: renderVerifiedBadge(isArtistVerified(song.artist), "Verified Artist"),
            }}
            handlers={{
                onPlay: () => playSong(song),
                onToggleLike: () => toggleLike(song.id),
                onToggleFollow: () => toggleArtistFollow(artistId, song.artist),
                onToggleSave: () => {
                    if (isSaved) {
                        removeFromLibrary(song.id);
                        return;
                    }
                    saveSongToLibrary(song);
                },
                onToggleQueue: () => {
                    if (isQueued) {
                        removeMediaFromQueue("song", song.id);
                        return;
                    }
                    addToQueue(song);
                },
                onOpenPlaylist: () => openPlaylistMenu(song),
                onDownload: () => { void downloadMediaFromCard("music", song.id, song.title); },
                onDelete: () => permanentDeleteSong(song.id, "Permanently delete this song?"),
                onOpenComments: () => openComments("song", song),
                onShare: () => copyShareLink("song", song.id, song.title),
                onReport: () => createModerationReport("song", song.id, song.title, "Community song report", song.artist, artistId),
                onClaim: () => createCopyrightClaim("song", song.id, song.title, song.artist),
                onOpenArtist: openArtistProfile,
            }}
        />);
    }
    function renderDesktopVideoCard(video: VideoItem, options: VideoCardOptions = {}) {
        const sourceLabel = options.sourceLabel || "Video Card";
        const artistId = createArtistId(video.creator);
        const isFollowing = followedArtistIds.includes(artistId);
        const isLiked = Boolean(video.likedByUser);
        const isSaved = savedVideoIds.includes(video.id);
        const isQueued = isMediaQueued("video", video.id);
        const canDeleteVideo = canDeleteUploadedVideo(video);
        const mobileIncompatible = isVideoMarkedMobileIncompatible(video);
        const downloadBusyKey = `video:${video.id}`;
        return (<DesktopVideoMediaCard
            key={video.id}
            video={{
                id: video.id,
                title: video.title,
                creator: video.creator,
                category: video.category,
                cover: video.cover,
                uploaded: video.uploaded,
                views: formatCount(video.views),
                likes: formatCount(video.likes || 0),
            }}
            variant={options.isLibraryCard ? "library" : "default"}
            likeLabel={options.unlikeLabel}
            state={{
                isLiked,
                isSaved,
                isFollowed: isFollowing,
                isQueued,
                isDownloading: mediaDownloadBusyKey === downloadBusyKey,
                canDelete: canDeleteVideo,
                canClaim: canClaimMedia,
                commentCount: getCommentsForItem("video", video.id).length,
                verifiedBadge: renderVerifiedBadge(isArtistVerified(video.creator), "Verified Artist"),
                mobileIncompatible,
                mobileCompatibilityWarning: mobileIncompatible ? getMobileVideoCompatibilityWarningText(video) : null,
            }}
            handlers={{
                onPlay: () => playVideo(video, sourceLabel),
                onToggleLike: () => toggleVideoLike(video),
                onToggleFollow: () => toggleArtistFollow(artistId, video.creator),
                onToggleSave: () => {
                    if (isSaved) {
                        removeVideoFromLibrary(video.id);
                        return;
                    }
                    handleSaveVideo(video.id);
                },
                onToggleQueue: () => {
                    if (isQueued) {
                        removeMediaFromQueue("video", video.id);
                        return;
                    }
                    addVideoToQueue(video);
                },
                onOpenPlaylist: () => handleVideoPlaylist(video.id),
                onDownload: () => { void downloadMediaFromCard("video", video.id, video.title); },
                onDelete: () => handlePermanentDeleteVideo(video.id),
                onOpenComments: () => openComments("video", video),
                onShare: () => copyShareLink("video", video.id, video.title),
                onReport: () => createModerationReport("video", video.id, video.title, "Community video report", video.creator, artistId),
                onClaim: () => createCopyrightClaim("video", video.id, video.title, video.creator),
                onOpenArtist: openArtistProfile,
            }}
        />);
    }
    function renderVideoCard(video: VideoItem, options: VideoCardOptions = {}) {
        return renderDesktopVideoCard(video, options);
    }
    async function addSongToPlaylist(playlistId: string, songId: string) {
        if (!playlistId || !songId) {
            showToast("Choose a playlist and song first.", "error");
            return;
        }
        const playlist = playlists.find((item) => item.id === playlistId);
        if (!playlist) {
            showToast("Choose a playlist first.", "error");
            return;
        }
        if (playlist.songIds.includes(songId)) {
            showToast("Already in this playlist.", "info");
            return;
        }
        const now = new Date().toISOString();
        setPlaylists((previous) => previous.map((playlist) => {
            if (playlist.id !== playlistId)
                return playlist;
            const songIds = uniqueIds([...playlist.songIds, songId]);
            return { ...playlist, songIds, updatedAt: now };
        }));
        if (!isUuid(playlistId)) {
            showToast("Added to playlist locally. Recreate this playlist to sync it to Supabase.", "info");
            pushNotification("New playlist add", `${songs.find((song) => song.id === songId)?.title || "Song"} was added to ${playlist.name}.`, "playlist", playlistId);
            setPlaylistTarget(null);
            return;
        }
        try {
            const playlistActionUserId = await resolveDesktopProtectedActionUserId("Log in before adding songs to playlists.");
            if (!playlistActionUserId) {
                return;
            }
            const response = await desktopActionFetch("/api/playlist-items", {
                requireAuth: true,
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ userId: playlistActionUserId, playlistId, itemId: songId, itemType: "song" }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
                alreadyAdded?: boolean;
            };
            if (!response.ok) {
                reportPlatformError("playlist", "add-song", data.error || "Playlist item sync failed.", { playlistId, songId });
                showToast("Added to playlist locally. Run playlist SQL to sync it to Supabase.", "info");
                setPlaylistTarget(null);
                return;
            }
            showToast(data.alreadyAdded ? "Already in this playlist." : "Added to playlist.", data.alreadyAdded ? "info" : "success");
            if (!data.alreadyAdded) {
                pushNotification("New playlist add", `${songs.find((song) => song.id === songId)?.title || "Song"} was added to ${playlist.name}.`, "playlist", playlistId);
            }
            setPlaylistTarget(null);
        }
        catch (error) {
            reportPlatformError("playlist", "add-song", error instanceof Error ? error.message : String(error), { playlistId, songId });
            showToast("Added to playlist locally. Run playlist SQL to sync it to Supabase.", "info");
            setPlaylistTarget(null);
        }
    }
