    function getProducerById(producerId: string) {
        if (!producerId)
            return null;
        if (currentProducerProfile.id === producerId)
            return currentProducerProfile;
        return producerProfiles.find((profile) => profile.id === producerId) || null;
    }
    async function getAlbumUploadUser() {
        let sessionUser: SupabaseUser | null = null;
        try {
            const { session } = await getAuthSession(supabase);
            if (!session?.user) {
                throw new Error("You must log in again before uploading.");
            }
            sessionUser = session.user;
        }
        catch (error) {
        }
        const uploadUser = sessionUser || albumUploadUserRef.current || user;
        if (!uploadUser?.id) {
            throw new Error("Sign in first before uploading an album.");
        }
        albumUploadUserRef.current = uploadUser;
        setUser((previous) => previous || uploadUser);
        return uploadUser;
    }
    function syncDesktopUploadSession(session: Session) {
        if (isDesktopVideoUploadLifecycleActive()) {
            noteValidatedDesktopSession(session);
            clearDesktopAuthRecoveryGate(session);
            return;
        }
        if (uploadInProgressRef.current) {
            noteValidatedDesktopSession(session);
            clearDesktopAuthRecoveryGate(session);
            return;
        }
        noteValidatedDesktopSession(session);
        clearDesktopAuthRecoveryGate(session);
        setAuthSession((previous) => {
            if (
                previous?.access_token === session.access_token
                && previous?.refresh_token === session.refresh_token
                && previous?.expires_at === session.expires_at
            ) {
                return previous;
            }
            return session;
        });
        setUser((previous) => previous || session.user);
    }
    async function uploadAudioToSupabase(file: File, songDetails: Pick<UploadForm, "title" | "artist" | "type" | "cover" | "producerId">, uploadUser?: SupabaseUser | null, albumId = "") {
        const fileError = getAudioFileError(file);
        if (fileError) {
            throw new Error(fileError);
        }
        let sessionUser = uploadUser || null;
        if (!sessionUser) {
            const { user } = await resolveDesktopUploadSession(supabase, {
                onSession: syncDesktopUploadSession,
            });
            sessionUser = user;
        }
        else {
            await resolveDesktopUploadSession(supabase, {
                onSession: syncDesktopUploadSession,
            });
        }
        assertUploadAllowed(sessionUser);
        if (!sessionUser?.id) {
            throw new Error("You must log in again before uploading.");
        }
        const sessionUserId = sessionUser.id;
        const storagePath = buildAudioStoragePath(sessionUserId, file);
        const contentType = getAudioUploadContentType(file);
        const producer = getProducerById(songDetails.producerId);
        const coverUrl = getArtworkUrl(songDetails.cover);

        setUploadStatus("Preparing upload...");
        setUploadProgress(4);
        setUploadStatus("Requesting signed Supabase Storage upload URL...");

        const prepareResponse = await desktopUploadFetch(supabase, "/api/upload-audio", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                mode: "prepare-storage-upload",
                sessionUserId,
                userId: sessionUserId,
                storagePath,
            }),
        }, { onSession: syncDesktopUploadSession });

        const prepareResult = (await prepareResponse.json().catch(() => ({}))) as {
            storagePath?: string;
            token?: string;
            signedUrl?: string;
            publicUrl?: string;
            error?: string;
            details?: unknown;
            bucket?: string;
        };

        let savedStoragePath = prepareResult.storagePath || storagePath;
        let publicUrl = prepareResult.publicUrl || "";

        if (!prepareResponse.ok || prepareResult.error || !prepareResult.token) {
            const prepareErrorDetails = prepareResult.details ? ` ${JSON.stringify(prepareResult.details)}` : "";
            const prepareFailureReason = prepareResult.error
                ? `${prepareResult.error}${prepareErrorDetails}`
                : `Signed upload prepare failed with HTTP ${prepareResponse.status}.`;
            console.warn("AUDIO UPLOAD SIGNED PREPARE FAILED, FALLING BACK TO DIRECT CLIENT UPLOAD", {
                reason: prepareFailureReason,
                bucket: SONGS_STORAGE_BUCKET,
                storagePath,
                userId: sessionUserId,
            });
            setUploadStatus("Uploading audio directly to Supabase Storage...");
            setUploadProgress(12);
            const directUpload = await supabase.storage.from(SONGS_STORAGE_BUCKET).upload(storagePath, file, {
                cacheControl: "3600",
                contentType,
                upsert: false,
            });
            if (directUpload.error) {
                throw new Error(`Direct Supabase Storage upload failed: ${directUpload.error.message}. Signed prepare error: ${prepareFailureReason}`);
            }
            savedStoragePath = directUpload.data?.path || storagePath;
            publicUrl = buildSongPublicUrl(savedStoragePath);
        }
        else {
            setUploadStatus("Uploading audio to Supabase Storage...");
            setUploadProgress(12);
            const storageUpload = await supabase.storage.from(SONGS_STORAGE_BUCKET).uploadToSignedUrl(
                prepareResult.storagePath || storagePath,
                prepareResult.token,
                file,
                {
                    cacheControl: "3600",
                    contentType,
                },
            );
            if (storageUpload.error) {
                console.warn("AUDIO SIGNED CLIENT UPLOAD FAILED, FALLING BACK TO DIRECT CLIENT UPLOAD", storageUpload.error);
                setUploadStatus("Retrying direct Supabase Storage upload...");
                const directUpload = await supabase.storage.from(SONGS_STORAGE_BUCKET).upload(storagePath, file, {
                    cacheControl: "3600",
                    contentType,
                    upsert: false,
                });
                if (directUpload.error) {
                    const signedClientError = storageUpload.error.message || "Supabase Storage signed upload failed.";
                    throw new Error(`Signed client upload failed (${signedClientError}). Direct fallback failed: ${directUpload.error.message}`);
                }
                savedStoragePath = directUpload.data?.path || storagePath;
                publicUrl = buildSongPublicUrl(savedStoragePath);
            }
            else {
                savedStoragePath = storageUpload.data?.path || prepareResult.storagePath || storagePath;
                publicUrl = prepareResult.publicUrl || buildSongPublicUrl(savedStoragePath);
            }
        }

        if (!publicUrl) {
            throw new Error("Supabase did not return a public URL for the uploaded audio.");
        }

        setUploadProgress(88);
        setUploadStatus("Saving song metadata...");
        const songInsertPayloadPreview = {
            user_id: sessionUserId,
            title: songDetails.title,
            artist: songDetails.artist,
            category: "New Releases",
            type: songDetails.type,
            cover_url: coverUrl,
            producer_id: producer?.id || "",
            producer: producer?.name || "",
            album_id: albumId || "",
            storage_path: savedStoragePath,
            audio_url: publicUrl,
        };
        console.error("INSERT USER ID:", songInsertPayloadPreview.user_id);
        console.error("AUTH USER ID:", sessionUserId);
        console.error("FULL INSERT PAYLOAD:", songInsertPayloadPreview);

        const metadataResponse = await desktopUploadFetch(supabase, "/api/upload-audio", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                mode: "save-metadata",
                sessionUserId,
                userId: sessionUserId,
                storagePath: savedStoragePath,
                publicUrl,
                title: songDetails.title,
                artist: songDetails.artist,
                category: "New Releases",
                type: songDetails.type,
                cover_url: coverUrl,
                producer_id: producer?.id || "",
                producer: producer?.name || "",
                album_id: albumId || "",
            }),
        }, { onSession: syncDesktopUploadSession });

        const responseText = await metadataResponse.text();
        let uploadResult: {
            publicUrl?: string;
            storagePath?: string;
            song?: SongTableRow;
            error?: string;
            details?: unknown;
        } = {};
        if (responseText) {
            try {
                uploadResult = JSON.parse(responseText) as typeof uploadResult;
            }
            catch {
                uploadResult = { error: responseText };
            }
        }
        if (!metadataResponse.ok) {
            const detailText = typeof uploadResult.details === "string"
                ? uploadResult.details
                : uploadResult.details
                    ? JSON.stringify(uploadResult.details)
                    : "";
            const responseDetails = uploadResult.details && typeof uploadResult.details === "object" ? uploadResult.details as Record<string, unknown> : {};
            const responseInsertPayload = responseDetails.insertPayload && typeof responseDetails.insertPayload === "object"
                ? responseDetails.insertPayload as Record<string, unknown>
                : songInsertPayloadPreview;
            console.error("INSERT USER ID:", responseDetails.insertUserId || responseInsertPayload.user_id || songInsertPayloadPreview.user_id);
            console.error("AUTH USER ID:", responseDetails.authUserId || sessionUserId);
            console.error("FULL INSERT PAYLOAD:", responseInsertPayload);
            console.error("SONG INSERT FAILED", uploadResult.error || metadataResponse.statusText, detailText);
            console.error("[music upload] INSERT FAILED public.songs:", uploadResult.error || metadataResponse.statusText, detailText);
            throw new Error([uploadResult.error || `Audio metadata save failed with HTTP ${metadataResponse.status}.`, detailText]
                .filter(Boolean)
                .join(" "));
        }
        if (!uploadResult.publicUrl) {
            throw new Error("Supabase did not return a public URL for the uploaded audio.");
        }
        if (!uploadResult.song) {
            throw new Error("Supabase uploaded the audio, but the server did not return the saved songs table row.");
        }
        setUploadProgress(98);
        setUploadStatus("Finishing upload...");
        setUploadProgress(100);
        return mapSongRowToSong(uploadResult.song);
    }
    async function uploadVideoToSupabase(file: File, videoDetails: Pick<VideoUploadForm, "title" | "creator" | "category" | "cover" | "producerId">, uploadUser?: SupabaseUser | null, albumId = "") {
        if (!guardDesktopProtectedAction("upload-video")) {
            throw new Error(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE);
        }
        const fileError = getVideoFileError(file);
        if (fileError) {
            throw new Error(fileError);
        }
        if (uploadUser?.id) {
            albumUploadUserRef.current = uploadUser;
        }
        const producer = getProducerById(videoDetails.producerId);
        const producerId = producer?.id || videoDetails.producerId || "";
        const storageAuthDebug = describeStorageUploadAuth();
        updateVideoUploadDebug({
            currentStep: "Starting desktop video upload",
            lastError: "",
            uploadMethod: "Signed Supabase Storage upload with direct-upload fallback",
            supabaseUrl: process.env.NEXT_PUBLIC_SUPABASE_URL || "",
            uploadTargetUrl: storageAuthDebug.storageUploadUrl,
            bucket: VIDEOS_STORAGE_BUCKET,
            fileSize: String(file.size),
            fileName: file.name,
            selectedFileName: file.name,
            selectedFileSize: String(file.size),
            hasFileObject: true,
            sourceLocation: "app/page.tsx uploadVideoToSupabase",
        });
        assertUploadAllowed(uploadUser || authSessionRef.current?.user || null);
        const uploadCredentials = await desktopRuntime.resolveCredentials({
            forceRefresh: true,
            authMode: "bearer-preferred",
        });
        if (!uploadCredentials?.session || uploadCredentials.transport.kind !== "bearer") {
            throw new Error(UPLOAD_REAUTH_MESSAGE);
        }
        syncDesktopUploadSession(uploadCredentials.session);
        const uploadResult = await runDesktopVideoUpload({
            supabase,
            file,
            pinnedSession: uploadCredentials.session,
            videoDetails: {
                title: videoDetails.title,
                creator: videoDetails.creator,
                category: videoDetails.category,
                cover: videoDetails.cover || DEFAULT_COVER,
                producerId: producerId || "",
                producerName: producer?.name || "",
                albumId: albumId || "",
            },
            onProgress: (update) => {
                applyVideoUploadProgressUpdate(update.status, update.percent);
            },
            onCodecInspected: (codecInfo) => {
                const debug = getDesktopVideoUploadCompatibilityDebug(codecInfo);
                updateVideoUploadDebug({
                    currentStep: codecInfo.canPublish ? "Codec inspection passed" : "Codec inspection rejected upload",
                    detectedContainer: debug.container,
                    detectedVideoCodec: debug.videoCodec,
                    detectedAudioCodec: debug.audioCodec,
                    detectedCompatible: debug.compatible,
                    detectedRejectionReason: debug.rejectionReason || "",
                    lastError: codecInfo.canPublish ? "" : (codecInfo.publicationError || debug.rejectionReason),
                });
            },
        });
        updateVideoUploadDebug({
            currentStep: "Video upload complete.",
            lastError: "",
            uploadMethod: uploadResult.uploadMethod,
            uploadTargetUrl: "/api/video-upload",
            requestMethod: "POST",
            requestBodyType: `${uploadResult.uploadMethod} storage upload + verified server metadata insert`,
            requestBodySize: String(file.size),
            fullInsertPayload: JSON.stringify(uploadResult.video || {}, null, 2),
            fullErrorJson: JSON.stringify({
                uploadMethod: uploadResult.uploadMethod,
                savedStoragePath: uploadResult.storagePath,
                publicUrl: uploadResult.publicUrl,
                bucket: VIDEOS_STORAGE_BUCKET,
            }, null, 2),
        });
        syncDesktopUploadSession(uploadResult.session);
        const savedVideo = uploadResult.video as VideoTableRow;
        if (!isUuid(savedVideo.id)) {
            throw new Error("Supabase inserted a video row without a real UUID id.");
        }
        return mapVideoRowToVideoItem(savedVideo);
    }
    async function copyStorageSetupSql() {
        try {
            await navigator.clipboard.writeText(STORAGE_SETUP_SQL);
            setStorageSetupCopied(true);
            window.setTimeout(() => setStorageSetupCopied(false), 1800);
        }
        catch {
            setUploadError("Copy failed. Your browser blocked clipboard access.");
        }
    }
    async function addUploadedSong(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        setUploadError("");
        setStorageSetupCopied(false);
        const uploadLockMessage = getUploadLockMessageForUser();
        if (uploadLockMessage) {
            setUploadError(uploadLockMessage);
            showToast(uploadLockMessage, "info");
            return;
        }
        const title = uploadForm.title.trim();
        const artist = uploadForm.artist.trim();
        if (!title || !artist) {
            setUploadError("Add a song title and artist name first.");
            return;
        }
        const fileError = getAudioFileError(uploadFile);
        if (fileError) {
            setUploadError(fileError);
            return;
        }
        setUploadBusy(true);
        setUploadProgress(1);
        setUploadStatus("Starting upload...");
        let uploadGuardActive = false;
        let uploadGuardKey = "";
        try {
            const selectedFile = uploadFile;
            if (!selectedFile) {
                setUploadError("Choose an MP3, WAV, or M4A audio file.");
                return;
            }
            uploadGuardKey = getUploadGuardKey("song", title, [selectedFile]);
            uploadGuardActive = beginUploadGuard(uploadGuardKey, "This song upload is already running.");
            if (!uploadGuardActive)
                return;
            let producerCreditId = uploadForm.producerId;
            if (creatorStudio === "producer") {
                const profile = currentProducerProfile.id ? currentProducerProfile : await saveProducerProfile();
                producerCreditId = profile.id;
            }
            const newSong = await uploadAudioToSupabase(selectedFile, {
                title,
                artist,
                type: uploadForm.type,
                cover: uploadForm.cover,
                producerId: producerCreditId,
            });
            const databaseSongs = await reloadSongLibraryFromSupabase();
            const savedSong = databaseSongs.find((song) => song.id === newSong.id) || newSong;
            saveToLibrary(savedSong);
            setCurrentSong(savedSong);
            setShowUpload(false);
            setUploadForm({
                title: "",
                artist: "",
                type: "Beats",
                cover: "",
                producerId: "",
            });
            setUploadFile(null);
            setUploadStatus("");
            if (creatorStudio === "producer") {
                setView("Producer Dashboard");
                showToast("Song uploaded to Producer Studio.", "success");
            } else {
                setView("Library");
            }
        }
        catch (error) {
            const message = getStorageErrorMessage(error, "audio");
            setUploadError(message);
            setUploadStatus("");
            reportPlatformError("upload", "song-upload", message, { title, artist });
        }
        finally {
            if (uploadGuardActive) {
                endUploadGuard(uploadGuardKey);
            }
            setUploadBusy(false);
        }
    }
    async function saveAccountRole(nextRole: AccountRole) {
        if (!user?.id) {
            showToast("Log in before changing account type.", "error");
            return;
        }
        if (foundingAccess?.isFoundingMember) {
            showToast(FOUNDING_ROLE_LOCKED_MESSAGE, "error");
            return;
        }
        const previousRole = accountRole;
        const previousNavRoles = accountNavRoles;
        setAccountRole(nextRole);
        setAccountNavRoles([nextRole.toLowerCase()]);
        try {
            const response = await fetch("/api/producers", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    action: "save-account-role",
                    userId: user.id,
                    accountType: nextRole.toLowerCase(),
                    skipProducerProfile: isPlatformOwner,
                    producerProfileId: currentProducerProfile.id,
                    name: producerProfileForm.name.trim() || currentProducerProfile.name,
                    avatar: producerProfileForm.avatar.trim() || currentProducerProfile.avatar,
                    banner: producerProfileForm.banner.trim() || currentProducerProfile.banner,
                    bio: producerProfileForm.bio.trim() || currentProducerProfile.bio,
                    tagline: producerProfileForm.tagline.trim() || currentProducerProfile.tagline,
                }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
                profile?: ProducerProfileTableRow;
                profileWarning?: string;
            };
            if (!response.ok) {
                setAccountRole(previousRole);
                setAccountNavRoles(previousNavRoles);
                showToast(data.error || "Account type could not be saved.", "error");
                return;
            }
            if (data.profile) {
                const savedProfile = mapProducerProfileRow(data.profile);
                setProducerProfiles((previous) => {
                    const remaining = previous.filter((profile) => profile.id !== savedProfile.id && profile.userId !== savedProfile.userId);
                    return [savedProfile, ...remaining];
                });
                setActiveProducerId(savedProfile.id);
                setProducerProfileForm({
                    name: savedProfile.name,
                    avatar: savedProfile.avatar,
                    banner: savedProfile.banner,
                    bio: savedProfile.bio,
                    tagline: savedProfile.tagline,
                    website: savedProfile.website,
                });
            }
            if (data.profileWarning) {
                showToast(`${nextRole} mode saved through creator profile. Profiles account_type needs setup.`, "info");
            }
            else {
                showToast(`${nextRole} account mode saved.`, "success");
            }
            await reloadUserProfileFromSupabase(user.id, user.email || "");
        }
        catch (error) {
            setAccountRole(previousRole);
            setAccountNavRoles(previousNavRoles);
            showToast("Account type could not be saved. Check your connection and try again.", "error");
        }
    }
    async function saveProducerProfile(event?: FormEvent<HTMLFormElement> | null, profileUser?: SupabaseUser | null) {
        event?.preventDefault();
        const ownerUser = profileUser || user;
        if (!ownerUser?.id) {
            showToast("Log in before saving a producer profile.", "error");
            return currentProducerProfile;
        }
        const nextProfile = {
            id: currentProducerProfile.id,
            userId: ownerUser.id,
            name: producerProfileForm.name.trim() || currentProducerProfile.name,
            avatar: producerProfileForm.avatar.trim() || currentProducerProfile.avatar,
            banner: producerProfileForm.banner.trim() || currentProducerProfile.banner,
            bio: producerProfileForm.bio.trim() || currentProducerProfile.bio,
            tagline: producerProfileForm.tagline.trim() || currentProducerProfile.tagline,
            website: producerProfileForm.website.trim() || currentProducerProfile.website,
        };
        const response = await fetch("/api/producers", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                action: "upsert-profile",
                ...nextProfile,
            }),
        });
        const data = (await response.json().catch(() => ({}))) as {
            profile?: ProducerProfileTableRow;
            error?: string;
        };
        if (!response.ok || !data.profile) {
            showToast(data.error || "Producer profile save failed.", "error");
            return currentProducerProfile;
        }
        const savedProfile = mapProducerProfileRow(data.profile);
        setProducerProfiles((previous) => {
            const remaining = previous.filter((profile) => profile.id !== savedProfile.id && profile.userId !== savedProfile.userId);
            return [savedProfile, ...remaining];
        });
        setActiveProducerId(savedProfile.id);
        setProducerProfileForm({
            name: savedProfile.name,
            avatar: savedProfile.avatar,
            banner: savedProfile.banner,
            bio: savedProfile.bio,
            tagline: savedProfile.tagline,
            website: savedProfile.website,
        });
        showToast("Producer profile saved.", "success");
        return savedProfile;
    }
    async function saveProducerBeatMetadata(song: Song, profile: ProducerProfile) {
        const response = await fetch("/api/producers", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                action: "upsert-beat",
                songId: song.id,
                producerId: profile.id,
                producerUserId: profile.userId,
                producerName: profile.name,
                title: song.title,
                category: song.type || "Beats",
                cover: song.cover,
                audioUrl: song.audio,
                storagePath: song.audioPath || "",
                license: producerLicense,
                leasePrice: producerLeasePrice,
                exclusivePrice: producerExclusivePrice,
                splitPercentage: clampProducerSplitShare(producerSplitPercentage),
            }),
        });
        const data = (await response.json().catch(() => ({}))) as {
            beat?: ProducerBeatTableRow;
            error?: string;
        };
        if (!response.ok || !data.beat) {
            throw new Error(data.error || "Producer beat metadata save failed.");
        }
        const beat = mapProducerBeatRow(data.beat);
        setProducerBeats((previous) => [beat, ...previous.filter((item) => item.id !== beat.id && item.songId !== beat.songId)]);
        return beat;
    }
    async function addUploadedProducerBeat(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        setUploadError("");
        setStorageSetupCopied(false);
        const uploadLockMessage = getUploadLockMessageForUser();
        if (uploadLockMessage) {
            setUploadError(uploadLockMessage);
            showToast(uploadLockMessage, "info");
            return;
        }
        const isInstrumental = uploadMode === "instrumental";
        const productLabel = isInstrumental ? "instrumental" : "beat";
        const title = uploadForm.title.trim();
        const producerName = uploadForm.artist.trim() || currentProducerProfile.name;
        if (!title || !producerName) {
            setUploadError(isInstrumental
                ? "Add an instrumental title and producer name first."
                : "Add a beat title and producer name first.");
            return;
        }
        const fileError = getAudioFileError(uploadFile);
        if (fileError) {
            setUploadError(fileError);
            return;
        }
        setUploadBusy(true);
        setUploadProgress(1);
        setUploadStatus(isInstrumental ? "Starting instrumental upload..." : "Starting beat upload...");
        let uploadGuardActive = false;
        let uploadGuardKey = "";
        try {
            if (!uploadFile) {
                setUploadError(isInstrumental
                    ? "Choose an MP3, WAV, or M4A instrumental file."
                    : "Choose an MP3, WAV, or M4A beat file.");
                return;
            }
            uploadGuardKey = getUploadGuardKey(productLabel, title, [uploadFile]);
            uploadGuardActive = beginUploadGuard(
                uploadGuardKey,
                isInstrumental
                    ? "This instrumental upload is already running."
                    : "This beat upload is already running.",
            );
            if (!uploadGuardActive)
                return;
            const profile = currentProducerProfile.id ? currentProducerProfile : await saveProducerProfile();
            const category = isInstrumental
                ? (uploadForm.type === "Instrumental" || BEAT_CATEGORIES.includes(uploadForm.type)
                    ? (uploadForm.type || "Instrumental")
                    : "Instrumental")
                : uploadForm.type;
            const newSong = await uploadAudioToSupabase(uploadFile, {
                title,
                artist: producerName,
                type: category,
                cover: uploadForm.cover,
                producerId: profile.id,
            });
            const beat = await saveProducerBeatMetadata(newSong, profile);
            await reloadSongLibraryFromSupabase();
            await reloadProducerDataFromSupabase();
            saveToLibrary({ ...newSong, producer: profile.name, producerId: profile.id, beatId: beat.id });
            setUploadForm({ title: "", artist: "", type: isInstrumental ? "Instrumental" : "Beats", cover: "", producerId: "" });
            setUploadFile(null);
            setUploadStatus("");
            setShowUpload(false);
            setCreatorStudio("producer");
            setView("Producer Dashboard");
            showToast(
                isInstrumental
                    ? "Instrumental uploaded to Producer Studio."
                    : "Beat uploaded to Producer Studio.",
                "success",
            );
        }
        catch (error) {
            const message = getStorageErrorMessage(error, "audio");
            setUploadError(message);
            setUploadStatus("");
            reportPlatformError("upload", `${productLabel}-upload`, message, { title, producerName });
        }
        finally {
            if (uploadGuardActive) {
                endUploadGuard(uploadGuardKey);
            }
            setUploadBusy(false);
        }
    }
    async function updateProducerBeat(beat: ProducerBeat, updates: Partial<ProducerBeat>) {
        const safeUpdates = updates.splitPercentage === undefined ? updates : { ...updates, splitPercentage: clampProducerSplitShare(updates.splitPercentage) };
        const nextBeat = { ...beat, ...safeUpdates };
        setProducerBeats((previous) => previous.map((item) => (item.id === beat.id ? nextBeat : item)));
        const response = await fetch("/api/producers", {
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({
                action: "update-beat",
                id: beat.id,
                license: safeUpdates.license,
                leasePrice: safeUpdates.leasePrice,
                exclusivePrice: safeUpdates.exclusivePrice,
                splitPercentage: safeUpdates.splitPercentage,
                plays: safeUpdates.plays,
                likes: safeUpdates.likes,
                downloads: safeUpdates.downloads,
                leases: safeUpdates.leases,
                payouts: safeUpdates.payouts,
            }),
        });
        if (!response.ok) {
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
            };
            showToast(data.error || "Producer beat update failed.", "error");
        }
    }
    async function permanentlyDeleteProducerBeat(beat: ProducerBeat) {
        if (!canDeleteProducerBeat(beat)) {
            showToast("Only the producer who uploaded this beat or owner admin can delete it.", "error");
            return;
        }
        if (!window.confirm(`Delete "${beat.title}" from Producer Beats?`))
            return;
        const previousBeats = producerBeats;
        setProducerBeats((previous) => previous.filter((item) => item.id !== beat.id));
        try {
            const response = await desktopActionFetch("/api/producers", {
                requireAuth: true,
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({
                    action: "delete-beat",
                    id: beat.id,
                    userId: desktopActionAuthGuard.getUserId(),
                }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
            };
            if (!response.ok) {
                setProducerBeats(previousBeats);
                showToast(data.error || "Producer beat could not be deleted.", "error");
                return;
            }
            showToast("Producer beat deleted.", "success");
        }
        catch (error) {
            setProducerBeats(previousBeats);
            showToast("Producer beat could not be deleted. Check your connection and try again.", "error");
        }
    }
    function playProducerBeat(beat: ProducerBeat) {
        const beatSong: Song = {
            id: beat.songId || beat.id,
            title: beat.title,
            artist: beat.producerName,
            producer: beat.producerName,
            producerId: beat.producerId,
            beatId: beat.id,
            category: "Producer Beats",
            type: beat.license,
            mediaKind: "audio",
            time: "3:00",
            plays: beat.plays,
            likes: beat.likes,
            uploaded: formatVideoCreatedAt(beat.createdAt),
            cover: beat.cover,
            avatar: beat.cover,
            audio: beat.audioUrl,
            audioPath: beat.storagePath,
            ownerId: beat.producerUserId,
        };
        updateProducerBeat(beat, { plays: beat.plays + 1 });
        playSong(beatSong);
    }
    function openProducerProfile(producerId: string) {
        setActiveProducerId(producerId);
        setView("Producer Profile");
    }
    async function addUploadedVideo(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        const uploadLockMessage = getUploadLockMessageForUser();
        if (uploadLockMessage) {
            setVideoUploadError(uploadLockMessage);
            showToast(uploadLockMessage, "info");
            return;
        }
        const submitForm = event.currentTarget;
        const stopUploadNetworkTrace = canViewVideoUploadDebug
            ? installVideoUploadNetworkTrace("app/page.tsx addUploadedVideo full Save Video flow", updateVideoUploadDebug)
            : () => undefined;
        setHasAttemptedVideoUpload(true);
        setVideoUploadError("");
        const mode = uploadMode;
        const sourceView = view;
        const title = videoForm.title.trim();
        const creator = videoForm.creator.trim() || (mode === "producerVideo" ? currentProducerProfile.name : "");
        const selectedVideoFile = getSelectedVideoUploadFile(submitForm);
        if (selectedVideoFile && selectedVideoFile !== videoFile) {
            selectedVideoFileRef.current = selectedVideoFile;
            setVideoFile(selectedVideoFile);
        }
        updateVideoUploadDebug({
            uploadMethod: "Save Video submit started",
            supabaseUrl: process.env.NEXT_PUBLIC_SUPABASE_URL || "",
            fileSize: selectedVideoFile ? String(selectedVideoFile.size) : "",
            fileName: selectedVideoFile?.name || "",
            selectedFileName: selectedVideoFile?.name || "",
            selectedFileSize: selectedVideoFile ? String(selectedVideoFile.size) : "",
            hasFileObject: Boolean(selectedVideoFile),
            currentStep: "Save Video clicked",
            lastError: "",
            fullErrorJson: "",
            sourceLocation: "app/page.tsx addUploadedVideo",
        });
        if (!title || !creator) {
            setVideoUploadError("Add a video title and creator name first.");
            updateVideoUploadDebug({
                currentStep: "Validation failed",
                lastError: "Add a video title and creator name first.",
            });
            stopUploadNetworkTrace();
            return;
        }
        const fileError = getVideoFileError(selectedVideoFile);
        if (fileError) {
            setVideoUploadError(fileError);
            updateVideoUploadDebug({
                currentStep: "File validation failed",
                lastError: fileError,
                hasFileObject: Boolean(selectedVideoFile),
            });
            stopUploadNetworkTrace();
            return;
        }
        let producerProfileForUpload: ProducerProfile | null = null;
        if (mode === "producerVideo") {
            producerProfileForUpload = currentProducerProfile.id ? currentProducerProfile : await saveProducerProfile();
            if (!producerProfileForUpload?.id) {
                setVideoUploadError("Save your producer profile before uploading a producer video.");
                updateVideoUploadDebug({
                    currentStep: "Producer profile validation failed",
                    lastError: "Save your producer profile before uploading a producer video.",
                });
                stopUploadNetworkTrace();
                return;
            }
        }
        const uploadUserId = requireDesktopUploadUserId("Log in before uploading a video.");
        if (!uploadUserId) {
            stopUploadNetworkTrace();
            return;
        }
        try {
            const uploadPreflight = await desktopRuntime.resolveCredentials({
                forceRefresh: true,
                authMode: "bearer-preferred",
            });
            if (!uploadPreflight?.session || uploadPreflight.transport.kind !== "bearer") {
                setVideoUploadError(UPLOAD_REAUTH_MESSAGE);
                showToast(UPLOAD_REAUTH_MESSAGE, "error");
                stopUploadNetworkTrace();
                return;
            }
            syncDesktopUploadSession(uploadPreflight.session);
        }
        catch (preflightError) {
            const message = preflightError instanceof Error ? preflightError.message : UPLOAD_REAUTH_MESSAGE;
            setVideoUploadError(message);
            showToast(message, "error");
            stopUploadNetworkTrace();
            return;
        }
        setVideoUploadBusy(true);
        let uploadGuardActive = false;
        let uploadGuardKey = "";
        let videoUploadSucceeded = false;
        try {
            if (!selectedVideoFile) {
                setVideoUploadError("Choose an MP4, MOV, or WEBM video file.");
                updateVideoUploadDebug({
                    currentStep: "File validation failed",
                    lastError: "Choose an MP4, MOV, or WEBM video file.",
                    hasFileObject: false,
                });
                return;
            }
            uploadGuardKey = getUploadGuardKey(mode, title, [selectedVideoFile]);
            uploadGuardActive = beginUploadGuard(uploadGuardKey, "This video upload is already running.");
            if (!uploadGuardActive)
                return;
            const newVideo = await uploadVideoToSupabase(selectedVideoFile, {
                title,
                creator: mode === "producerVideo" ? producerProfileForUpload?.name || creator : creator,
                category: videoForm.category,
                cover: videoForm.cover,
                producerId: producerProfileForUpload?.id || videoForm.producerId,
            });
            setVideos((previous) => uniqueVideos([newVideo, ...previous]));
            setSelectedVideoId(newVideo.id);
            setActiveVideo(newVideo);
            setVideoUploadStep("Reloading video library...", 99);
            try {
                const databaseVideos = await reloadVideoLibraryFromSupabase();
                await reloadProducerDataFromSupabase();
                const savedVideo = databaseVideos.find((video) => video.id === newVideo.id) || newVideo;
                setActiveVideo(savedVideo);
                setSelectedVideoId(savedVideo.id);
            }
            catch (reloadError) {
                console.warn("[video upload] dashboard refresh after save failed:", reloadError);
            }
            setVideoForm({ title: "", creator: "", category: "Music Video", cover: "", producerId: "" });
            selectedVideoFileRef.current = null;
            setVideoFile(null);
            setVideoUploadStatus("");
            updateVideoUploadDebug({
                currentStep: "Video upload saved and loaded.",
                lastError: "",
            });
            setView(mode === "producerVideo" ? "Producer Dashboard" : sourceView === "Artist Dashboard" ? "Artist Dashboard" : "Videos");
            showToast(mode === "producerVideo" ? "Producer video uploaded." : "Video uploaded.", "success");
            videoUploadSucceeded = true;
            setVideoUploadProgress(0);
            setVideoUploadStatus("");
        }
        catch (error) {
            let message = getVideoUploadErrorMessage(error);
            if (error instanceof Error && error.name === "AbortError") {
                message = DESKTOP_VIDEO_UPLOAD_STALL_ERROR_MESSAGE;
            }
            if (message === DESKTOP_VIDEO_UPLOAD_STALL_ERROR_MESSAGE || (error instanceof Error && error.name === "DesktopVideoUploadStallError")) {
                message = DESKTOP_VIDEO_UPLOAD_STALL_ERROR_MESSAGE;
            }
            if (message === SESSION_EXPIRED_MESSAGE && authSessionRef.current) {
                message = error instanceof Error && error.message !== SESSION_EXPIRED_MESSAGE
                    ? error.message
                    : "Video metadata save failed. Please retry save.";
            }
            setVideoUploadError(message);
            setVideoUploadStatus("");
            setVideoUploadProgress(0);
            updateVideoUploadDebug({
                currentStep: "Upload failed",
                lastError: message,
                fullErrorJson: stringifyUploadDebugError(error),
            });
            stopUploadNetworkTrace();
            reportPlatformError("upload", mode === "producerVideo" ? "producer-video-upload" : "video-upload", message, { title, creator });
        }
        finally {
            if (uploadGuardActive) {
                endUploadGuard(uploadGuardKey);
            }
            if (!videoUploadSucceeded) {
                setVideoUploadProgress(0);
                setVideoUploadStatus("");
            }
            else if (authSessionRef.current) {
                syncDesktopUploadSession(authSessionRef.current);
            }
            setVideoUploadBusy(false);
            stopUploadNetworkTrace();
        }
    }
    type AlbumSavePayload = {
        albumId: string;
        userId: string;
        title: string;
        creatorName: string;
        ownerType: AlbumOwnerType;
        artistName: string;
        artistId: string;
        producerName: string;
        producerId: string;
        producerProfileId: string;
        coverUrl: string;
        category: string;
        releaseDate: string;
    };
    async function createAlbumRowInSupabase(payload: AlbumSavePayload) {
        const response = await desktopActionFetch("/api/albums/create", {
            requireAuth: true,
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify(payload),
        });
        const data = (await response.json().catch(() => ({}))) as {
            album?: Album;
            recentAlbums?: Album[];
            error?: string;
        };
        if (!response.ok || !data.album) {
            throw new Error(data.error || "Album row could not be created.");
        }
        const album = normalizeAlbumRecord(data.album);
        if (!album.id || !isUuid(album.id)) {
            throw new Error("Album row was created without a valid album id.");
        }
        return album;
    }
    async function verifyAlbumRowExistsInSupabase(payload: AlbumSavePayload, album: Album) {
        const albumsAfterCreate = await loadAlbums(payload.userId);
        const verifiedAlbum = albumsAfterCreate.find((item) => item.id === album.id);
        if (verifiedAlbum) {
            return verifiedAlbum;
        }
        return createAlbumRowInSupabase(payload);
    }
    async function saveAlbumItemsToSupabase(albumId: string, userId: string, items: {
        itemId: string;
        itemType: "song" | "video";
    }[]) {
        if (!albumId || !isUuid(albumId)) {
            throw new Error("Album id is required before saving album items.");
        }
        const response = await desktopActionFetch("/api/albums/items", {
            requireAuth: true,
            method: "POST",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ albumId, userId, items }),
        });
        const data = (await response.json().catch(() => ({}))) as {
            album?: Album;
            error?: string;
        };
        if (!response.ok || !data.album) {
            throw new Error(data.error || "Album items could not be saved.");
        }
        const album = normalizeAlbumRecord(data.album);
        return album;
    }
    async function addUploadedAlbum(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        setAlbumUploadError("");
        setAlbumUploadStatus("");
        const uploadLockMessage = getUploadLockMessageForUser();
        if (uploadLockMessage) {
            setAlbumUploadError(uploadLockMessage);
            showToast(uploadLockMessage, "info");
            return;
        }
        const ownerType: AlbumOwnerType = uploadMode === "producerAlbum" ? "producer" : "artist";
        const title = albumForm.title.trim();
        if (!title) {
            setAlbumUploadError("Add an album title first.");
            return;
        }
        if (albumSongFiles.length === 0) {
            setAlbumUploadError("Add at least one song to upload an album.");
            return;
        }
        const songFileError = albumSongFiles.map((file) => getAudioFileError(file)).find(Boolean);
        if (songFileError) {
            setAlbumUploadError(songFileError);
            return;
        }
        const videoFileError = albumVideoFiles.map((file) => getVideoFileError(file)).find(Boolean);
        if (videoFileError) {
            setAlbumUploadError(videoFileError);
            return;
        }
        let uploadUser: SupabaseUser;
        try {
            uploadUser = await getAlbumUploadUser();
        }
        catch (error) {
            const message = error instanceof Error ? error.message : "Sign in first before uploading an album.";
            setAlbumUploadError(message);
            showToast(message, "error");
            return;
        }
        const albumUploadFiles = [...albumSongFiles, ...albumVideoFiles];
        const albumUploadKey = getUploadGuardKey(ownerType === "producer" ? "producer-album" : "album", title, albumUploadFiles);
        const albumGuardActive = beginUploadGuard(albumUploadKey, "This album upload is already running.");
        if (!albumGuardActive) {
            setAlbumUploadError("This album upload is already running.");
            return;
        }
        setAlbumUploadBusy(true);
        setAlbumUploadProgress(1);
        setAlbumUploadStatus("Starting album upload...");
        try {
            const producerProfile = ownerType === "producer"
                ? currentProducerProfile.id
                    ? currentProducerProfile
                    : await saveProducerProfile(null, uploadUser)
                : null;
            const creatorName = albumForm.creatorName.trim() ||
                (ownerType === "producer"
                    ? producerProfile?.name || currentProducerProfile.name
                    : selectedDashboardArtist?.name ||
                        getAccountDisplayName(uploadUser) ||
                        uploadUser.email?.split("@")[0] ||
                        "Artist");
            if (ownerType === "producer" && !producerProfile?.id) {
                setAlbumUploadError("Save your producer profile before uploading a producer album.");
                return;
            }
            const coverUrl = getArtworkUrl(albumForm.cover);
            const category = albumForm.category.trim() || "Album";
            const totalSteps = albumSongFiles.length + albumVideoFiles.length + 2;
            let completedSteps = 0;
            const uploadedSongs: Song[] = [];
            const uploadedVideos: VideoItem[] = [];
            setAlbumUploadStatus("Creating album...");
            const albumPayload = {
                albumId: crypto.randomUUID(),
                userId: uploadUser.id,
                title,
                creatorName,
                ownerType,
                artistName: ownerType === "artist" ? creatorName : "",
                artistId: ownerType === "artist" ? uploadUser.id : "",
                producerName: ownerType === "producer" ? creatorName : "",
                producerId: producerProfile?.id || "",
                producerProfileId: producerProfile?.id || "",
                coverUrl,
                category,
                releaseDate: albumForm.releaseDate,
            };
            let albumRow = await createAlbumRowInSupabase(albumPayload);
            setAlbums((previous) => [albumRow, ...previous.filter((album) => album.id !== albumRow.id)]);
            completedSteps += 1;
            setAlbumUploadProgress(Math.round((completedSteps / totalSteps) * 100));
            for (const [index, file] of albumSongFiles.entries()) {
                setAlbumUploadStatus(`Uploading song ${index + 1} of ${albumSongFiles.length}...`);
                const song = await uploadAudioToSupabase(file, {
                    title: getUploadTitleFromFile(file, `${title} Song ${index + 1}`),
                    artist: creatorName,
                    type: category,
                    cover: coverUrl,
                    producerId: producerProfile?.id || "",
                }, uploadUser, albumRow.id);
                uploadedSongs.push(song);
                completedSteps += 1;
                setAlbumUploadProgress(Math.round((completedSteps / totalSteps) * 100));
            }
            for (const [index, file] of albumVideoFiles.entries()) {
                setAlbumUploadStatus(`Uploading video ${index + 1} of ${albumVideoFiles.length}...`);
                const video = await uploadVideoToSupabase(file, {
                    title: getUploadTitleFromFile(file, `${title} Video ${index + 1}`),
                    creator: creatorName,
                    category,
                    cover: coverUrl,
                    producerId: producerProfile?.id || "",
                }, uploadUser, albumRow.id);
                uploadedVideos.push(video);
                completedSteps += 1;
                setAlbumUploadProgress(Math.round((completedSteps / totalSteps) * 100));
            }
            setAlbumUploadStatus("Saving album items...");
            const albumItems = [
                ...uploadedSongs.map((song) => ({ itemId: song.id, itemType: "song" as const })),
                ...uploadedVideos.map((video) => ({ itemId: video.id, itemType: "video" as const })),
            ];
            albumRow = await verifyAlbumRowExistsInSupabase(albumPayload, albumRow);
            let createdAlbum: Album;
            try {
                createdAlbum = await saveAlbumItemsToSupabase(albumRow.id, uploadUser.id, albumItems);
            }
            catch (error) {
                albumRow = await createAlbumRowInSupabase(albumPayload);
                createdAlbum = await saveAlbumItemsToSupabase(albumRow.id, uploadUser.id, albumItems);
            }
            completedSteps += 1;
            setAlbumUploadProgress(Math.round((completedSteps / totalSteps) * 100));
            setAlbums((previous) => [createdAlbum, ...previous.filter((album) => album.id !== createdAlbum.id)]);
            const [, , refreshedAlbums] = await Promise.all([
                reloadSongLibraryFromSupabase(),
                reloadVideoLibraryFromSupabase(),
                loadAlbums(uploadUser.id),
                reloadProducerDataFromSupabase(),
            ]);
            if (!refreshedAlbums.some((album) => album.id === createdAlbum.id)) {
                const fallbackAlbum = await createAlbumRowInSupabase(albumPayload);
                const fallbackAlbumWithItems = await saveAlbumItemsToSupabase(fallbackAlbum.id, uploadUser.id, albumItems);
                setAlbums((previous) => [
                    fallbackAlbumWithItems,
                    ...previous.filter((album) => album.id !== fallbackAlbumWithItems.id),
                ]);
                await loadAlbums(uploadUser.id);
            }
            setDashboardArtistId((previous) => previous || createArtistId(creatorName));
            if (ownerType === "producer" && producerProfile?.id) {
                setActiveProducerId(producerProfile.id);
            }
            setAlbumForm({ title: "", creatorName: "", cover: "", category: "Album", releaseDate: "" });
            setAlbumSongFiles([]);
            setAlbumVideoFiles([]);
            setAlbumUploadProgress(100);
            setAlbumUploadStatus("");
            setShowUpload(false);
            setView(ownerType === "producer" ? "Producer Dashboard" : "Artist Dashboard");
            showToast("Album uploaded successfully.", "success");
        }
        catch (error) {
            const message = error instanceof Error ? error.message : "Album upload failed.";
            setAlbumUploadError(message);
            showToast(message, "error");
            reportPlatformError("upload", ownerType === "producer" ? "producer-album-upload" : "album-upload", message, { title, songs: albumSongFiles.length, videos: albumVideoFiles.length });
        }
        finally {
            endUploadGuard(albumUploadKey);
            setAlbumUploadBusy(false);
            albumUploadUserRef.current = null;
        }
    }
    function playVideo(video: VideoItem | Record<string, unknown>, sourceSection = "Video Card") {
        stopRingtonePreviewPlayback();
        if (sourceSection !== "Shared Queue") {
            setForcedQueuePlayableUrl("");
        }
        const playableVideo = normalizeVideo(video);
        const incomingPlayableUrl = sourceSection === "Shared Queue"
            ? String(
                (video as { playableUrl?: string }).playableUrl
                || (video as { videoUrl?: string }).videoUrl
                || (video as { video_url?: string }).video_url
                || "",
            ).trim()
            : "";
        const videoUrl = getVideoPlaybackUrl(playableVideo) || incomingPlayableUrl;
        if (!videoUrl) {
            console.error("[video play] missing playable URL:", sourceSection, playableVideo.id, playableVideo.title);
            reportPlatformError("media_url", "play-video-missing-url", "Video file URL missing", {
                sourceSection,
                videoId: playableVideo.id,
                title: playableVideo.title,
            });
            setVideoPlaying(false);
            setVideoProgress(0);
            setVideoDuration(0);
            setActiveMedia((previous) => (previous?.type === "video" ? null : previous));
            setActiveVideo((previous) => (previous?.id === playableVideo.id ? null : previous));
            showToast("Video file URL missing", "error");
            reloadVideoLibraryFromSupabase().catch((error) => console.error("[video play] refresh after missing URL failed:", error));
            return;
        }
        const nextViews = (playableVideo.views || 0) + 1;
        const nextActiveVideo = {
            ...playableVideo,
            views: nextViews,
            videoUrl: videoUrl || playableVideo.videoUrl || "",
            video_url: videoUrl || playableVideo.video_url || "",
        };
        console.log("[video selected]", {
            sourceSection,
            selectedVideoId: playableVideo.id,
            title: playableVideo.title,
            video_url: playableVideo.video_url,
            storage_path: playableVideo.storagePath || playableVideo.storage_path || "",
            fileName: playableVideo.fileName || "",
            finalVideoUrl: videoUrl,
            extension: getVideoUrlExtension(videoUrl),
        });
        void logVideoPlaybackProbe(playableVideo, videoUrl, sourceSection);
        const shouldUseNativeMobileControls = isMobilePlaybackEnvironment();
        const mobilePlaybackBlocked = shouldUseNativeMobileControls
            && shouldBlockMobileVideoPlayback(videoUrl, nextActiveVideo);
        if (mobilePlaybackBlocked) {
            showToast(getMobileVideoCompatibilityWarningText(nextActiveVideo, videoUrl), "error");
        }
        if (audioRef.current) {
            audioRef.current.pause();
            audioRef.current.removeAttribute("src");
            audioRef.current.load();
        }
        flushSync(() => {
            setIsPlaying(false);
            setCurrentSong(null);
            setActiveMediaType("video");
            setActiveMedia({ type: "video", item: nextActiveVideo });
            setActiveVideo(nextActiveVideo);
            setSelectedVideoId(playableVideo.id);
            setVideoProgress(0);
            setVideoDuration(0);
        });
        const mainVideo = mainVideoRef.current;
        if (mobilePlaybackBlocked) {
            if (mainVideo) {
                mainVideo.pause();
                mainVideo.removeAttribute("src");
                mainVideo.load();
            }
            pendingVideoPlayRef.current = false;
            if (shouldUseNativeMobileControls && !isNavigationScrollLocked()) {
                mainVideo?.scrollIntoView({ behavior: "smooth", block: "center" });
            }
            return;
        }
        if (mainVideo) {
            mainVideo.setAttribute("playsinline", "");
            mainVideo.setAttribute("webkit-playsinline", "");
            mainVideo.controls = true;
            mainVideo.autoplay = false;
            mainVideo.preload = "metadata";
            mainVideo.muted = false;
            mainVideo.volume = videoVolume;
            if (mainVideo.getAttribute("src") !== videoUrl) {
                mainVideo.pause();
                mainVideo.src = videoUrl;
                mainVideo.load();
            }
            console.log("[video play attempt]", {
                sourceSection,
                selectedVideoId: playableVideo.id,
                finalVideoUrl: videoUrl,
                desktopUrl: videoUrl,
                mobileUrl: videoUrl,
                desktopMobileUrlMatch: true,
                actualVideoSrc: mainVideo.currentSrc || mainVideo.src || mainVideo.getAttribute("src") || "",
                playsInline: mainVideo.playsInline,
                controls: mainVideo.controls,
                muted: mainVideo.muted,
                autoplay: mainVideo.autoplay,
                preload: mainVideo.preload,
                readyState: mainVideo.readyState,
                networkState: mainVideo.networkState,
                mediaErrorCode: mainVideo.error?.code || null,
                mediaErrorMessage: mainVideo.error?.message || "",
            });
            logVideoElementState("playVideo prepared", mainVideo, {
                sourceSection,
            });
            if (shouldUseNativeMobileControls) {
                pendingVideoPlayRef.current = false;
                mainVideo.controls = true;
                if (!isNavigationScrollLocked()) {
                    mainVideo.scrollIntoView({ behavior: "smooth", block: "center" });
                }
                return;
            }
            mainVideo.play().then(() => {
                setVideoPlaying(true);
            }).catch((error) => {
                setVideoPlaying(false);
                console.warn("[video play attempt failed]", {
                    sourceSection,
                    selectedVideoId: playableVideo.id,
                    finalVideoUrl: videoUrl,
                    actualVideoSrc: mainVideo.currentSrc || mainVideo.src || mainVideo.getAttribute("src") || "",
                    readyState: mainVideo.readyState,
                    networkState: mainVideo.networkState,
                    mediaErrorCode: mainVideo.error?.code || null,
                    mediaErrorMessage: mainVideo.error?.message || "",
                    error,
                });
                const message = error instanceof Error ? error.message : String(error);
                if (isMobilePlaybackEnvironment()) {
                    pendingVideoPlayRef.current = false;
                    if (mainVideo.error?.code === 4 || shouldBlockMobileVideoPlayback(videoUrl, nextActiveVideo, mainVideo)) {
                        showToast(getMobileVideoPlaybackDiagnosticMessage(nextActiveVideo, videoUrl, mainVideo.error?.code), "error");
                        return;
                    }
                    return;
                }
                if (isDeferredVideoPlayError(error)) {
                    pendingVideoPlayRef.current = true;
                    showToast("Video is loading. If it does not start, press Play again.", "info");
                    return;
                }
                if (!message.toLowerCase().includes("interrupted")) {
                    showToast("Video playback could not start. Try pressing Play again.", "error");
                }
            });
        }
        else {
            setVideoAutoplayRequestId(playableVideo.id);
        }
        saveVideoPlay(nextActiveVideo);
        if (!sourceSection.includes("Album") && !isActiveAlbumTrack("video", playableVideo.id)) {
            setActiveAlbumPlayback(null);
        }
        setView("Videos");
        setVideos((previous) => previous.some((item) => item.id === playableVideo.id)
            ? previous.map((item) => (item.id === playableVideo.id ? { ...normalizeVideoForPlayback(item), views: nextViews } : item))
            : uniqueVideos([nextActiveVideo, ...previous]));
        window.requestAnimationFrame(() => {
            window.requestAnimationFrame(() => {
                if (!isNavigationScrollLocked()) {
                    videoPreviewRef.current?.scrollIntoView({ behavior: "smooth", block: "start" });
                }
            });
        });
        fetch(`/api/videos/${encodeURIComponent(playableVideo.id)}`, {
            method: "PATCH",
            headers: { "Content-Type": "application/json" },
            body: JSON.stringify({ views: nextViews }),
        })
            .then(async (response) => {
            if (!response.ok) {
                const data = (await response.json().catch(() => ({}))) as {
                    error?: string;
                };
                showToast("Video is playing, but view count did not save.", "error");
            }
        })
            .catch((error) => {
            showToast("Video is playing, but view count did not save.", "error");
        });
    }
    function playAdjacentVideo(direction: "previous" | "next") {
        if (mediaQueueItems.length > 0) {
            const nextItem = direction === "next" ? advanceSharedQueueNext() : advanceSharedQueuePrevious();
            if (nextItem) {
                playQueuedMediaItem(nextItem);
                return;
            }
        }
        const list = getVideoPlaybackList();
        if (list.length === 0)
            return;
        const currentIndex = Math.max(0, list.findIndex((video) => video.id === activeVideo?.id));
        const nextIndex = direction === "next"
            ? (currentIndex + 1) % list.length
            : (currentIndex - 1 + list.length) % list.length;
        playVideo(list[nextIndex], "Video Player Controls");
    }
    async function toggleVideoLike(video: VideoItem) {
        const actionUserId = await resolveDesktopProtectedActionUserId("Log in before liking videos.");
        if (!actionUserId) {
            return;
        }
        const previousLikes = video.likes || 0;
        const shouldLike = !video.likedByUser;
        const optimisticLikes = shouldLike ? previousLikes + 1 : Math.max(0, previousLikes - 1);
        setVideos((previous) => previous.map((item) => item.id === video.id ? { ...item, likes: optimisticLikes, likedByUser: shouldLike } : item));
        setActiveVideo((previous) => previous?.id === video.id ? { ...previous, likes: optimisticLikes, likedByUser: shouldLike } : previous);
        try {
            const response = await desktopActionFetch(`/api/videos/${encodeURIComponent(video.id)}`, {
                requireAuth: true,
                method: "PATCH",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ like: shouldLike, userId: actionUserId }),
            });
            const data = (await response.json().catch(() => ({}))) as {
                error?: string;
                likes?: number;
                likedByUser?: boolean;
            };
            if (!response.ok) {
                setVideos((previous) => previous.map((item) => item.id === video.id ? { ...item, likes: previousLikes, likedByUser: video.likedByUser } : item));
                setActiveVideo((previous) => previous?.id === video.id ? { ...previous, likes: previousLikes, likedByUser: video.likedByUser } : previous);
                const message = data.error || `Could not ${shouldLike ? "like" : "unlike"} this video.`;
                showToast(message, "error");
                reportPlatformError("like", shouldLike ? "video-like" : "video-unlike", message, {
                    videoId: video.id,
                    title: video.title,
                });
                return;
            }
            const nextLikedVideoState = {
                likes: typeof data.likes === "number" ? data.likes : optimisticLikes,
                likedByUser: Boolean(data.likedByUser),
            };
            setVideos((previous) => previous.map((item) => item.id === video.id
                ? {
                    ...item,
                    ...nextLikedVideoState,
                }
                : item));
            setActiveVideo((previous) => previous?.id === video.id ? { ...previous, ...nextLikedVideoState } : previous);
            showToast(data.likedByUser ? "Video liked." : "Video unliked.", "success");
            if (data.likedByUser) {
                pushNotification("New like", `${video.title} was liked.`, "video", video.id);
            }
        }
        catch (error) {
            setVideos((previous) => previous.map((item) => item.id === video.id ? { ...item, likes: previousLikes, likedByUser: video.likedByUser } : item));
            setActiveVideo((previous) => previous?.id === video.id ? { ...previous, likes: previousLikes, likedByUser: video.likedByUser } : previous);
            const message = error instanceof Error ? error.message : `Could not ${shouldLike ? "like" : "unlike"} this video. Check your connection and try again.`;
            showToast(message, "error");
            reportPlatformError("like", shouldLike ? "video-like" : "video-unlike", message, {
                videoId: video.id,
                title: video.title,
            });
        }
    }
    async function permanentlyDeleteVideo(videoId: string) {
        const video = videos.find((item) => item.id === videoId);
        if (!video)
            return;
        if (!canDeleteUploadedVideo(video)) {
            showToast("Only the uploader or owner admin can delete this video.", "error");
            return;
        }
        if (!window.confirm("Permanently delete this video?"))
            return;
        const previousState = {
            videos,
            libraryIds,
            savedVideoIds,
            activeVideo,
            selectedVideoId,
            activeMedia,
            activeMediaType,
            videoPlaying,
            videoProgress,
            videoDuration,
        };
        purgeDeletedVideoFromUi(videoId);
        try {
            const response = await desktopActionFetch(`/api/videos/${encodeURIComponent(videoId)}?userId=${encodeURIComponent(desktopActionAuthGuard.getUserId())}`, {
                requireAuth: true,
                method: "DELETE",
            });
            if (!response.ok) {
                const data = (await response.json().catch(() => ({}))) as {
                    error?: string;
                };
                setVideos(previousState.videos);
                setLibraryIds(previousState.libraryIds);
                setSavedVideoIds(previousState.savedVideoIds);
                setActiveVideo(previousState.activeVideo);
                setSelectedVideoId(previousState.selectedVideoId);
                setActiveMedia(previousState.activeMedia);
                setActiveMediaType(previousState.activeMediaType);
                setVideoPlaying(previousState.videoPlaying);
                setVideoProgress(previousState.videoProgress);
                setVideoDuration(previousState.videoDuration);
                restoreVideoLocalStorageSnapshot(previousState);
                showToast(data.error || "Video could not be deleted from Supabase.", "error");
                return;
            }
            await reloadVideoLibraryFromSupabase().catch((refreshError) => {
                showToast("Video deleted, but the refreshed video list could not load yet.", "error");
            });
            showToast("Video deleted.", "success");
        }
        catch (error) {
            setVideos(previousState.videos);
            setLibraryIds(previousState.libraryIds);
            setSavedVideoIds(previousState.savedVideoIds);
            setActiveVideo(previousState.activeVideo);
            setSelectedVideoId(previousState.selectedVideoId);
            setActiveMedia(previousState.activeMedia);
            setActiveMediaType(previousState.activeMediaType);
            setVideoPlaying(previousState.videoPlaying);
            setVideoProgress(previousState.videoProgress);
            setVideoDuration(previousState.videoDuration);
            restoreVideoLocalStorageSnapshot(previousState);
            showToast("Video could not be deleted. Check your connection and try again.", "error");
        }
    }
