    function saveArtistProfile(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        if (!selectedDashboardArtist)
            return;
        const nextName = artistProfileValues.name.trim() || selectedDashboardArtist.name;
        const nextId = createArtistId(nextName);
        const previousId = selectedDashboardArtist.id;
        const nextProfile: ArtistProfile = {
            id: nextId,
            name: nextName,
            banner: artistProfileValues.banner.trim() || DEFAULT_ARTIST_BANNER,
            avatar: getArtworkUrl(artistProfileValues.avatar),
            bio: artistProfileValues.bio.trim() || `${nextName} is building a catalog on Z Music.`,
            socialLinks: artistProfileValues.socialLinks.trim(),
            monthlyListeners: Math.max(0, Number(artistProfileValues.monthlyListeners) || 0),
            followers: Math.max(0, Number(artistProfileValues.followers) || 0),
            totalPlays: selectedDashboardArtist.totalPlays,
        };
        setSongs((previous) => previous.map((song) => createArtistId(song.artist) === previousId
            ? { ...song, artist: nextName, avatar: nextProfile.avatar }
            : song));
        setArtistProfiles((previous) => {
            const remaining = previous.filter((artist) => artist.id !== previousId && artist.id !== nextId);
            return uniqueArtists([nextProfile, ...remaining]);
        });
        setFollowedArtistIds((previous) => uniqueIds(previous.map((id) => (id === previousId ? nextId : id))));
        setDashboardArtistId(nextId);
        setActiveArtistId((previous) => (previous === previousId ? nextId : previous));
    }
    function getAuthErrorMessage(error: unknown) {
        if (error instanceof Error) {
            if (error.message === "Failed to fetch") {
                return "Could not reach Supabase. Check your Supabase URL, anon key, internet connection, and allowed site URL settings.";
            }
            return error.message;
        }
        return "Something went wrong while connecting to Supabase. Please try again.";
    }
    async function handleAuthSubmit(event: FormEvent<HTMLFormElement>) {
        event.preventDefault();
        setAuthMessage("");
        setAuthBusy(true);
        const email = authEmail.trim();
        const password = authPassword;
        if (!email || !password) {
            setAuthMessage("Enter your email and password.");
            setAuthBusy(false);
            return;
        }
        try {
            const signupDisplayName = authName.trim() || email.split("@")[0];
            if (authMode === "signup" && foundingBetaLocked && !isPlatformOwnerEmail(email)) {
                if (!authInviteCode.trim()) {
                    setAuthMessage(FOUNDING_INVITE_REQUIRED_MESSAGE);
                    return;
                }
                const validation = await fetch("/api/founding-invites/validate", {
                    method: "POST",
                    headers: { "Content-Type": "application/json" },
                    body: JSON.stringify({ inviteCode: authInviteCode }),
                });
                const validationJson = await validation.json().catch(() => ({}));
                if (!validation.ok || !validationJson.valid) {
                    setAuthMessage(validationJson.error || FOUNDING_INVITE_REQUIRED_MESSAGE);
                    return;
                }
            }
            const response = authMode === "signup"
                ? await supabase.auth.signUp({
                    email,
                    password,
                    options: {
                        data: buildSignupUserMetadata({ displayName: signupDisplayName }),
                    },
                })
                : await supabase.auth.signInWithPassword({ email, password });
            if (response.error) {
                setAuthMessage(response.error.message);
                return;
            }
            if (authMode === "signup" && !response.data.session) {
                setAuthMessage("Account created. Check your email to confirm your sign up.");
                return;
            }
            markDesktopAuthSignInPending();
            authBootstrapOutcomeKeyRef.current = "";
            const signedInSession = response.data.session;
            const activeSession = await completeDesktopSignIn(supabase, signedInSession);
            if (!activeSession?.user) {
                setAuthMessage("Login succeeded but your session could not be restored. Please try again.");
                return;
            }

            completeSignIn(activeSession);
            setUserAuthProfile((previous) => ({
                ...previous,
                displayName: signupDisplayName,
            }));

            await syncUserAuthProfile(activeSession.user.id, {
                action: "ensure",
                displayName: signupDisplayName,
            }).catch(() => undefined);
            if (authMode === "signup" && foundingBetaLocked && !isPlatformOwnerEmail(email) && authInviteCode.trim()) {
                const redeem = await fetch("/api/founding-invites/redeem", {
                    method: "POST",
                    headers: {
                        Authorization: `Bearer ${activeSession.access_token}`,
                        "Content-Type": "application/json",
                    },
                    body: JSON.stringify({
                        userId: activeSession.user.id,
                        sessionUserId: activeSession.user.id,
                        accessToken: activeSession.access_token,
                        sessionAccessToken: activeSession.access_token,
                        refreshToken: activeSession.refresh_token,
                        sessionRefreshToken: activeSession.refresh_token,
                        inviteCode: authInviteCode,
                        displayName: signupDisplayName,
                    }),
                });
                const redeemJson = await redeem.json().catch(() => ({}));
                if (!redeem.ok) {
                    setAuthMessage(redeemJson.error || "Invite redemption failed.");
                    return;
                }
            }
            const access = await reloadFoundingAccess(activeSession.user.id, activeSession.access_token);
            // Reload authoritative capabilities before choosing a destination.
            const profileAfterLogin = await reloadUserProfileFromSupabase(
                activeSession.user.id,
                activeSession.user.email || email,
            );
            setAuthEmail("");
            setAuthPassword("");
            setAuthName("");
            setAuthInviteCode("");
            setAuthMessage(authMode === "signup"
                ? "Account created. Your founding application is pending owner approval."
                : "Welcome back.");
            // Never navigate from founding invite role (e.g. founding_artist → Artist Dashboard).
            // Listener account_type must land on Home even when founding_members is approved.
            const primaryAfterLogin = String(profileAfterLogin?.role || "listener").trim().toLowerCase();
            const nextView = resolvePostAuthDestination({
                isPlatformOwner: isPlatformOwnerEmail(activeSession.user.email),
                canArtistDashboard: primaryAfterLogin === "artist" || primaryAfterLogin === "admin",
                canProducerDashboard: primaryAfterLogin === "producer" || primaryAfterLogin === "admin",
            }) as View;
            if (access?.canAccessApp !== false) {
                setShowUpload(false);
                setToast(null);
                setView(nextView);
            }
            if (typeof console !== "undefined") {
                console.info(ACCOUNT_ACCESS_TRACE_PREFIX, "post-login-destination", {
                    nextView,
                    primaryAfterLogin,
                    foundingDashboardIgnored: access?.suggestedCreatorDashboard || access?.dashboardView || null,
                    foundingRole: access?.foundingRole || null,
                    foundingApproval: access?.approvalStatus || null,
                });
            }
        }
        catch (error) {
            setAuthMessage(getAuthErrorMessage(error));
        }
        finally {
            setAuthBusy(false);
        }
    }
    async function handleGateRedeemInvite() {
        setGateRedeemMessage("");
        setGateRedeemMessageTone("");
        const session = authSessionRef.current;
        const userId = session?.user?.id || accountUserIdRef.current || "";
        const accessToken = session?.access_token || "";
        const refreshToken = session?.refresh_token || "";
        if (!userId || !accessToken) {
            setGateRedeemMessageTone("error");
            setGateRedeemMessage("Log in before redeeming an invite.");
            return;
        }
        const inviteCode = authInviteCode.trim();
        if (!inviteCode) {
            setGateRedeemMessageTone("error");
            setGateRedeemMessage(FOUNDING_INVITE_REQUIRED_MESSAGE);
            return;
        }
        setGateRedeemBusy(true);
        try {
            const validation = await fetch("/api/founding-invites/validate", {
                method: "POST",
                headers: { "Content-Type": "application/json" },
                body: JSON.stringify({ inviteCode }),
            });
            const validationJson = await validation.json().catch(() => ({}));
            if (!validation.ok || !validationJson.valid) {
                setGateRedeemMessageTone("error");
                setGateRedeemMessage(validationJson.error || FOUNDING_INVITE_REQUIRED_MESSAGE);
                return;
            }

            const redeem = await fetch("/api/founding-invites/redeem", {
                method: "POST",
                headers: {
                    Authorization: `Bearer ${accessToken}`,
                    "Content-Type": "application/json",
                },
                body: JSON.stringify({
                    userId,
                    sessionUserId: userId,
                    accessToken,
                    sessionAccessToken: accessToken,
                    refreshToken,
                    sessionRefreshToken: refreshToken,
                    inviteCode,
                    displayName: getAccountDisplayName(),
                }),
            });
            const redeemJson = await redeem.json().catch(() => ({}));
            if (!redeem.ok) {
                setGateRedeemMessageTone("error");
                setGateRedeemMessage(redeemJson.error || "Invite redemption failed.");
                return;
            }

            const access = await reloadFoundingAccess(userId, accessToken);
            await reloadUserProfileFromSupabase(userId);
            setAuthInviteCode("");
            setGateRedeemMessageTone("success");
            if (access?.canAccessApp) {
                setGateRedeemMessage(t("auth.redeemInviteSuccessApproved"));
                // Founding approval must not force Artist/Producer Dashboard for Listener profiles.
                setShowUpload(false);
                setToast(null);
                setView("Home");
                return;
            }
            setGateRedeemMessage(t("auth.redeemInviteSuccess"));
        }
        catch (error) {
            setGateRedeemMessageTone("error");
            setGateRedeemMessage(getAuthErrorMessage(error));
        }
        finally {
            setGateRedeemBusy(false);
        }
    }
    async function logout() {
        setAuthMessage("");
        try {
            await signOutFromAuthState();
        }
        catch (error) {
            console.error("Logout failed:", error);
        }
        finally {
            resetQueueOnLogout();
            clearLocalSessionState();
        }
    }
    function applyDesktopView(nextView: View) {
        // Exactly one destination workspace: always unmount upload chrome when leaving via nav.
        setToast(null);
        setShowUpload(false);
        setShowNotificationCenter(false);
        setView(nextView);
        if (nextView === "Artist Dashboard") {
            setCreatorStudio("artist");
            setUploadMode("song");
        }
        if (nextView === "Producer Dashboard") {
            setCreatorStudio("producer");
            setUploadMode("beat");
        }
        if (nextView === "Platform Control Center") {
            window.setTimeout(() => {
                void loadLaunchStatus();
                void loadPlatformStabilityReport();
                void loadLaunchChecklist();
            }, 0);
        }
        if (nextView === "Home") {
            setActiveTab("Trending");
        }
        if (nextView === "Notifications") {
            void reloadNotificationsFromServer();
        }
        // Explicit nav action: pin destination heading under sticky topbar (not mere scrollTop=0).
        scheduleNavigationScrollReset({ focusHeading: true, ensureUploadVisible: false });
    }
    function denyUnauthorizedDesktopNav() {
        setToast(null);
        setShowUpload(false);
        showToast(ACCOUNT_ROLE_UNAVAILABLE_MESSAGE, "error");
        if (view !== "Home") {
            applyDesktopView("Home");
            return;
        }
        scheduleNavigationScrollReset({ focusHeading: true, ensureUploadVisible: false });
    }
    function handleNav(nextView: View) {
        setShowNotificationCenter(false);
        setToast(null);
        // FoundingMemberGate already blocks unapproved app access. Navigation uses
        // server-trusted role capabilities only — never founding invite leftovers.
        const accessDecision = evaluateDesktopNavAccess(nextView as DesktopNavView, desktopNavAccess);
        if (!accessDecision.allowed) {
            denyUnauthorizedDesktopNav();
            return;
        }
        applyDesktopView(nextView);
    }
    function openProfileFromHeader() {
        handleNav("Profile");
        if (typeof window !== "undefined" && window.matchMedia("(max-width: 820px)").matches) {
            router.push("/#profile", { scroll: false });
        }
    }
    function toggleUploadPanel() {
        if (!shouldShowUploadControl(desktopNavAccess)) {
            showToast("Upload is available for Artist and Producer accounts.", "error");
            return;
        }
        if (uploadsBlockedForCurrentUser) {
            showToast(UPLOAD_LOCK_MESSAGE, "info");
            return;
        }
        if (!protectedActionsReady) {
            showToast(DESKTOP_PROTECTED_API_LOGIN_REQUIRED_MESSAGE, "error");
            return;
        }
        const opening = !showUpload;
        if (opening) {
            const nextStudio = resolveCreatorStudio({
                preferStudio: creatorStudio,
                canArtistDashboard: shouldShowArtistDashboardControl(desktopNavAccess),
                canProducerDashboard: shouldShowProducerDashboardControl(desktopNavAccess),
                view,
            });
            setCreatorStudio(nextStudio);
            if (view === "Videos" && nextStudio === "artist") {
                setUploadMode("video");
            } else {
                setUploadMode(defaultUploadModeForStudio(nextStudio));
            }
        }
        setShowUpload(opening ? true : false);
        if (opening) {
            scheduleNavigationScrollReset({ focusHeading: false, ensureUploadVisible: true });
        }
    }
    function selectUploadMode(nextMode: typeof uploadMode) {
        setUploadMode(nextMode);
        if (nextMode === "instrumental") {
            setUploadForm((previous) => ({ ...previous, type: "Instrumental" }));
        } else if (nextMode === "beat") {
            setUploadForm((previous) => ({ ...previous, type: previous.type === "Instrumental" ? "Beats" : previous.type || "Beats" }));
        }
        if (showUpload) {
            scheduleNavigationScrollReset({ focusHeading: false, ensureUploadVisible: true });
        }
    }
    function switchCreatorStudio(nextStudio: CreatorStudioKind) {
        setCreatorStudio(nextStudio);
        setUploadMode(defaultUploadModeForStudio(nextStudio));
        if (nextStudio === "artist" && view === "Producer Dashboard" && shouldShowArtistDashboardControl(desktopNavAccess)) {
            setView("Artist Dashboard");
        }
        if (nextStudio === "producer" && view === "Artist Dashboard" && shouldShowProducerDashboardControl(desktopNavAccess)) {
            setView("Producer Dashboard");
        }
        if (!showUpload) {
            setShowUpload(true);
        }
        scheduleNavigationScrollReset({ focusHeading: false, ensureUploadVisible: true });
    }
